class Solution:
    def maxIncreasingCells(self, mat) -> int:
        m, n = len(mat), len(mat[0])
        memo = {}
        def neighbors(r, c):
            v = mat[r][c]
            res = []
            for cc in range(n):
                if cc != c and mat[r][cc] > v:
                    res.append((r, cc))
            for rr in range(m):
                if rr != r and mat[rr][c] > v:
                    res.append((rr, c))
            return res
        def dp(r, c):
            if (r, c) in memo:
                return memo[(r, c)]
            best = 1
            for (rr, cc) in neighbors(r, c):
                cand = 1 + dp(rr, cc)
                if cand > best:
                    best = cand
            memo[(r, c)] = best
            return best
        return max(dp(r, c) for r in range(m) for c in range(n))

