class Solution:
    def maxIncreasingCells(self, mat) -> int:
        from collections import defaultdict
        m, n = len(mat), len(mat[0])
        value_cells = defaultdict(list)
        for r in range(m):
            for c in range(n):
                value_cells[mat[r][c]].append((r, c))
        row_best = [0] * m
        col_best = [0] * n
        ans = 0
        for v in sorted(value_cells.keys()):
            cells = value_cells[v]
            dp_vals = []
            for (r, c) in cells:
                dp = max(row_best[r], col_best[c]) + 1
                dp_vals.append(dp)
                if dp > ans:
                    ans = dp
            for (r, c), dp in zip(cells, dp_vals):
                if dp > row_best[r]:
                    row_best[r] = dp
                if dp > col_best[c]:
                    col_best[c] = dp
        return ans

