var maxIncreasingCells = function(mat) {
    const m = mat.length, n = mat[0].length;
    const valueCells = new Map();
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            const v = mat[r][c];
            if (!valueCells.has(v)) valueCells.set(v, []);
            valueCells.get(v).push([r, c]);
        }
    }
    const rowBest = new Array(m).fill(0);
    const colBest = new Array(n).fill(0);
    const values = Array.from(valueCells.keys()).sort((a, b) => a - b);
    let ans = 0;
    for (const v of values) {
        const cells = valueCells.get(v);
        const dpVals = [];
        for (const [r, c] of cells) {
            const dp = Math.max(rowBest[r], colBest[c]) + 1;
            dpVals.push(dp);
            if (dp > ans) ans = dp;
        }
        for (let i = 0; i < cells.length; i++) {
            const [r, c] = cells[i];
            const dp = dpVals[i];
            if (dp > rowBest[r]) rowBest[r] = dp;
            if (dp > colBest[c]) colBest[c] = dp;
        }
    }
    return ans;
};
